package com.day7.pack;

public class LargeNum {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int a = 10;
        int b = 20;

        if (a > b) {
            System.out.println("Largest number is: " + a);
        }

        if (b > a) {
            System.out.println("Largest number is: " + b);
        }
	}

}
